from typing import Dict, List, Tuple, Union, Hashable, Any

AdjList = Dict[
    Hashable,
    List[Union[Hashable, Tuple[Hashable, Any], List[Union[Hashable, Any]]]]
]

def generate_nodes_from_adj(adj: AdjList):
    seen = set()
    ordered_nodes = []

    for u, nbrs in adj.items():
        if u not in seen:
            seen.add(u)
            ordered_nodes.append(u)

        for item in nbrs:
            if isinstance(item, (tuple, list)):  # weighted neighbor form
                if item:  # avoid empty []
                    v = item[0]
                else:
                    continue
            else:  # unweighted neighbor form
                v = item

            if v not in seen:
                seen.add(v)
                ordered_nodes.append(v)

    # Generate a valid 'nodes' argument
    if not ordered_nodes:
        return None  # no nodes -> let nx compute default (empty result)
    if len(ordered_nodes) == 1:
        return ordered_nodes[0]  # singleton node
    return ordered_nodes[0]```
